import React, { useEffect, useState, useCallback } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid, ResponsiveContainer } from 'recharts';

const BASE = "http://localhost:5000/api/dashboard";

/* ========================================
   ADMIN DASHBOARD
   ======================================== */
export function AdminDashboard({ onLogout }) {
  const [page, setPage] = useState('dashboard');
  const [data, setData] = useState(null);
  const [beneficiaries, setBeneficiaries] = useState([]);
  const [shops, setShops] = useState([]);
  const [stock, setStock] = useState([]);
  const [reports, setReports] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Modals
  const [showAddShop, setShowAddShop] = useState(false);
  const [showUpdateStock, setShowUpdateStock] = useState(false);
  const [newShop, setNewShop] = useState({ name: '', location: '' });
  const [stockUpdate, setStockUpdate] = useState({ shop_id: '', rice: '', wheat: '' });

  const loadDashboard = useCallback(() => {
    fetch(`${BASE}/admin`).then(r => r.json()).then(setData);
  }, []);

  useEffect(() => { loadDashboard(); }, [loadDashboard]);

  useEffect(() => {
    if (page === 'beneficiaries') fetch(`${BASE}/admin/beneficiaries`).then(r => r.json()).then(setBeneficiaries);
    if (page === 'shops') fetch(`${BASE}/admin/shops`).then(r => r.json()).then(setShops);
    if (page === 'stock') fetch(`${BASE}/admin/stock`).then(r => r.json()).then(setStock);
    if (page === 'reports') fetch(`${BASE}/admin/reports`).then(r => r.json()).then(setReports);
  }, [page]);

  const handleAddShop = async () => {
    const res = await fetch(`${BASE}/admin/shops`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newShop)
    });
    if (res.ok) { alert('Shop added!'); setShowAddShop(false); setNewShop({ name: '', location: '' }); loadDashboard(); if(page === 'shops') fetch(`${BASE}/admin/shops`).then(r => r.json()).then(setShops); }
    else alert('Error adding shop');
  };

  const handleUpdateStock = async () => {
    const res = await fetch(`${BASE}/admin/stock`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(stockUpdate)
    });
    if (res.ok) { alert('Stock updated!'); setShowUpdateStock(false); setStockUpdate({ shop_id: '', rice: '', wheat: '' }); loadDashboard(); if(page === 'stock') fetch(`${BASE}/admin/stock`).then(r => r.json()).then(setStock); }
    else alert('Error updating stock');
  };

  if (!data) return <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', color: '#555' }}>Loading Dashboard...</div>;

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '🏠' },
    { id: 'beneficiaries', label: 'Beneficiaries', icon: '📋' },
    { id: 'shops', label: 'Ration Shops', icon: '🏪' },
    { id: 'stock', label: 'Stock', icon: '📦' },
    { id: 'reports', label: 'Reports', icon: '📊' }
  ];

  const filteredDistributions = data.recentDistributions.filter(d =>
    !searchTerm || (d.beneficiaryName && d.beneficiaryName.toLowerCase().includes(searchTerm.toLowerCase())) || (d.aadhaar && d.aadhaar.includes(searchTerm))
  );

  return (
    <div className="admin-layout">
      {/* Sidebar */}
      <div className="sidebar">
        <div className="sidebar-header">
          <span>🏠</span>
          <div>Smart Ration<br/>Distribution System</div>
        </div>

        <div className="sidebar-profile">
          <div className="avatar">👤</div>
          <p>Welcome Admin</p>
          <span>admin@ration.gov.in</span>
        </div>

        <div className="sidebar-nav">
          {navItems.map(item => (
            <div key={item.id} className={`sidebar-nav-item ${page === item.id ? 'active' : ''}`} onClick={() => setPage(item.id)}>
              <span className="icon">{item.icon}</span>
              {item.label}
            </div>
          ))}
        </div>

        <div className="sidebar-logout">
          <button onClick={onLogout}>⎋ Logout</button>
        </div>
      </div>

      {/* Main Content */}
      <div className="main-content">
        <div className="topbar">
          <div className="admin-badge">
            <div className="avatar-sm">👤</div>
            Admin
          </div>
          <button className="logout-btn" onClick={onLogout}>Logout</button>
        </div>

        {/* Dashboard Page */}
        {page === 'dashboard' && (
          <div className="dashboard-content">
            <div className="welcome-section">
              <h2>Welcome to the Smart Ration Distribution System</h2>
              <p>Manage beneficiaries, ration shops, and stock efficiently and transparently.</p>
            </div>

            <div className="stat-cards">
              <div className="stat-card green">
                <div className="stat-label">👥 Beneficiaries</div>
                <div className="stat-number">{data.beneficiaryCount}</div>
                <div className="stat-sub">Beneficiaries</div>
                <button className="stat-btn" onClick={() => setPage('beneficiaries')}>View All ➜</button>
              </div>
              <div className="stat-card orange">
                <div className="stat-label">🏪 Ration Shops</div>
                <div className="stat-number">{data.shopCount}</div>
                <div className="stat-sub">Ration Shops</div>
                <button className="stat-btn" onClick={() => setShowAddShop(true)}>Add Shop +</button>
              </div>
              <div className="stat-card blue">
                <div className="stat-label">📦 Stock</div>
                <div className="stat-number">{data.totalStock}</div>
                <div className="stat-sub">Total Allocated (kg)</div>
                <button className="stat-btn" onClick={() => setShowUpdateStock(true)}>Update Stock +</button>
              </div>
            </div>

            <div className="content-grid">
              <div className="card">
                <div className="card-header">
                  <h3>Recent Distributions</h3>
                  <div className="search-bar">
                    🔍 <input placeholder="Search..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                  </div>
                </div>
                <table className="data-table">
                  <thead>
                    <tr>
                      <th>Id</th>
                      <th>Beneficiary Name</th>
                      <th>Aadhaar No.</th>
                      <th>Shop</th>
                      <th>Date</th>
                      <th>Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredDistributions.length > 0 ? filteredDistributions.map((tx, idx) => (
                      <tr key={idx}>
                        <td>{tx.id}</td>
                        <td>{tx.beneficiaryName || '-'}</td>
                        <td>{tx.aadhaar || '-'}</td>
                        <td>{tx.shopName || '-'}</td>
                        <td>{new Date(tx.date).toLocaleDateString()}</td>
                        <td><span className="status-delivered">Delivered</span></td>
                      </tr>
                    )) : (
                      <tr><td colSpan="6" style={{ textAlign: 'center', color: '#999', padding: '30px' }}>No distributions yet</td></tr>
                    )}
                  </tbody>
                </table>
                <div className="view-all">
                  <a onClick={() => setPage('reports')}>View All ›</a>
                </div>
              </div>

              <div className="summary-cards">
                <div className="summary-card">
                  <div className="summary-icon blue">📦</div>
                  <div className="summary-text">
                    <h4>Total Stock</h4>
                    <p>{data.totalStock} kg</p>
                  </div>
                </div>
                <div className="summary-card">
                  <div className="summary-icon green">🚚</div>
                  <div className="summary-text">
                    <h4>Distributed Stock</h4>
                    <p>{data.distributedStock} kg</p>
                  </div>
                </div>
                <div className="summary-card">
                  <div className="summary-icon red">⚠️</div>
                  <div className="summary-text">
                    <h4>Low Stock Alerts</h4>
                    <p>{data.lowStockAlerts}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Beneficiaries Page */}
        {page === 'beneficiaries' && (
          <div className="sub-page">
            <h2>All Beneficiaries</h2>
            <div className="card">
              <table className="data-table">
                <thead>
                  <tr>
                    <th>ID</th><th>Name</th><th>Aadhaar</th><th>Ration Card</th><th>Category</th><th>Family</th><th>Mobile</th><th>City</th><th>Verified</th>
                  </tr>
                </thead>
                <tbody>
                  {beneficiaries.map((u, i) => (
                    <tr key={i}>
                      <td>{u.id}</td><td>{u.name}</td><td>{u.aadhaar}</td><td>{u.ration_card_number}</td>
                      <td>{u.ration_category}</td><td>{u.family_members}</td><td>{u.mobile_number}</td><td>{u.city}</td>
                      <td>{u.is_verified ? '✅' : '❌'}</td>
                    </tr>
                  ))}
                  {beneficiaries.length === 0 && <tr><td colSpan="9" style={{ textAlign: 'center', color: '#999', padding: '30px' }}>No beneficiaries found</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Shops Page */}
        {page === 'shops' && (
          <div className="sub-page">
            <div className="top-bar-actions">
              <h2>Ration Shops</h2>
              <button className="add-btn" onClick={() => setShowAddShop(true)}>+ Add Shop</button>
            </div>
            <div className="card">
              <table className="data-table">
                <thead>
                  <tr><th>ID</th><th>Name</th><th>Location</th><th>Rice (kg)</th><th>Wheat (kg)</th></tr>
                </thead>
                <tbody>
                  {shops.map((s, i) => (
                    <tr key={i}><td>{s.id}</td><td>{s.name}</td><td>{s.location}</td><td>{s.rice ?? 0}</td><td>{s.wheat ?? 0}</td></tr>
                  ))}
                  {shops.length === 0 && <tr><td colSpan="5" style={{ textAlign: 'center', color: '#999', padding: '30px' }}>No shops found</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Stock Page */}
        {page === 'stock' && (
          <div className="sub-page">
            <div className="top-bar-actions">
              <h2>Stock Management</h2>
              <button className="add-btn" onClick={() => setShowUpdateStock(true)}>+ Update Stock</button>
            </div>
            <div className="card" style={{ marginBottom: '20px' }}>
              <h3>Stock Overview</h3>
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={stock.map(s => ({ name: s.shopName || `Shop ${s.shop_id}`, Rice: s.rice, Wheat: s.wheat }))}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="name" />
                  <YAxis />
                  <Tooltip />
                  <Bar dataKey="Rice" fill="#27ae60" radius={[5,5,0,0]} />
                  <Bar dataKey="Wheat" fill="#e67e22" radius={[5,5,0,0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
            <div className="card">
              <table className="data-table">
                <thead>
                  <tr><th>Shop ID</th><th>Shop Name</th><th>Location</th><th>Rice (kg)</th><th>Wheat (kg)</th><th>Total (kg)</th></tr>
                </thead>
                <tbody>
                  {stock.map((s, i) => (
                    <tr key={i}><td>{s.shop_id}</td><td>{s.shopName || '-'}</td><td>{s.location || '-'}</td><td>{s.rice}</td><td>{s.wheat}</td><td>{s.rice + s.wheat}</td></tr>
                  ))}
                  {stock.length === 0 && <tr><td colSpan="6" style={{ textAlign: 'center', color: '#999', padding: '30px' }}>No stock data</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Reports Page */}
        {page === 'reports' && (
          <div className="sub-page">
            <h2>All Transaction Reports</h2>
            <div className="card">
              <table className="data-table">
                <thead>
                  <tr><th>ID</th><th>Beneficiary</th><th>Aadhaar</th><th>Shop</th><th>Rice (kg)</th><th>Wheat (kg)</th><th>Date</th></tr>
                </thead>
                <tbody>
                  {reports.map((tx, i) => (
                    <tr key={i}><td>{tx.id}</td><td>{tx.beneficiaryName || '-'}</td><td>{tx.aadhaar || '-'}</td><td>{tx.shopName || '-'}</td><td>{tx.rice}</td><td>{tx.wheat}</td><td>{new Date(tx.date).toLocaleDateString()}</td></tr>
                  ))}
                  {reports.length === 0 && <tr><td colSpan="7" style={{ textAlign: 'center', color: '#999', padding: '30px' }}>No transactions found</td></tr>}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>

      {/* Add Shop Modal */}
      {showAddShop && (
        <div className="modal-overlay" onClick={() => setShowAddShop(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3>Add New Shop</h3>
            <input className="modal-input" placeholder="Shop Name" value={newShop.name} onChange={e => setNewShop({...newShop, name: e.target.value})} />
            <input className="modal-input" placeholder="Location" value={newShop.location} onChange={e => setNewShop({...newShop, location: e.target.value})} />
            <div className="modal-actions">
              <button className="modal-btn cancel" onClick={() => setShowAddShop(false)}>Cancel</button>
              <button className="modal-btn primary" onClick={handleAddShop}>Add Shop</button>
            </div>
          </div>
        </div>
      )}

      {/* Update Stock Modal */}
      {showUpdateStock && (
        <div className="modal-overlay" onClick={() => setShowUpdateStock(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3>Update Stock</h3>
            <input className="modal-input" placeholder="Shop ID" type="number" value={stockUpdate.shop_id} onChange={e => setStockUpdate({...stockUpdate, shop_id: e.target.value})} />
            <input className="modal-input" placeholder="Rice (kg)" type="number" value={stockUpdate.rice} onChange={e => setStockUpdate({...stockUpdate, rice: e.target.value})} />
            <input className="modal-input" placeholder="Wheat (kg)" type="number" value={stockUpdate.wheat} onChange={e => setStockUpdate({...stockUpdate, wheat: e.target.value})} />
            <div className="modal-actions">
              <button className="modal-btn cancel" onClick={() => setShowUpdateStock(false)}>Cancel</button>
              <button className="modal-btn primary" onClick={handleUpdateStock}>Update</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ========================================
   SHOPKEEPER DASHBOARD
   ======================================== */
export function ShopkeeperDashboard({ onLogout, shopId = 1 }) {
  const [data, setData] = useState(null);
  const [search, setSearch] = useState("");
  const [userResult, setUserResult] = useState(null);
  const [distribute, setDistribute] = useState({ rice: 0, wheat: 0 });

  const loadData = useCallback(() => {
    fetch(`${BASE}/shopkeeper/${shopId}`).then(r => r.json()).then(setData);
  }, [shopId]);

  useEffect(() => { loadData(); }, [loadData]);

  const handleSearch = async () => {
    const res = await fetch(`${BASE}/shopkeeper/search`, {
      method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ aadhaar: search })
    });
    if (res.ok) setUserResult(await res.json());
    else { alert("User not found"); setUserResult(null); }
  };

  const handleDistribute = async () => {
    const res = await fetch(`${BASE}/shopkeeper/distribute`, {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ user_id: userResult.id, shop_id: shopId, rice: distribute.rice, wheat: distribute.wheat })
    });
    if (res.ok) { alert(await res.text()); loadData(); setUserResult(null); }
    else alert("Error distributing ration");
  };

  if (!data) return <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', color: '#555' }}>Loading...</div>;

  return (
    <div style={{ padding: '30px', maxWidth: '1000px', margin: 'auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
        <h2 style={{ color: '#1e3a5f' }}>Shopkeeper Dashboard</h2>
        <button className="add-btn" style={{ background: '#e74c3c' }} onClick={onLogout}>Logout</button>
      </div>

      <div className="stat-cards">
        <div className="stat-card green">
          <div className="stat-label">🌾 Rice Stock</div>
          <div className="stat-number">{data.currentStock.rice}</div>
          <div className="stat-sub">kg</div>
        </div>
        <div className="stat-card orange">
          <div className="stat-label">🌾 Wheat Stock</div>
          <div className="stat-number">{data.currentStock.wheat}</div>
          <div className="stat-sub">kg</div>
        </div>
        <div className="stat-card blue">
          <div className="stat-label">📋 Daily Transactions</div>
          <div className="stat-number">{data.dailyTransactions.length}</div>
          <div className="stat-sub">Today</div>
        </div>
      </div>

      <div className="card" style={{ marginBottom: '20px' }}>
        <h3>Distribute Ration (Search User)</h3>
        <div style={{ display: 'flex', gap: '10px', marginBottom: '15px' }}>
          <input className="modal-input" placeholder="Search by Aadhaar" style={{ marginBottom: 0 }} onChange={e => setSearch(e.target.value)} />
          <button className="add-btn" onClick={handleSearch}>Search</button>
        </div>

        {userResult && (
          <div style={{ padding: '15px', background: '#f9f9fb', borderRadius: '10px' }}>
            <p><strong>Name:</strong> {userResult.name}</p>
            <p><strong>Ration Card:</strong> {userResult.ration_card_number} ({userResult.ration_category})</p>
            <p><strong>Family Members:</strong> {userResult.family_members}</p>
            <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
              <input type="number" className="modal-input" placeholder="Rice (kg)" style={{ marginBottom: 0 }} onChange={e => setDistribute({...distribute, rice: e.target.value})} />
              <input type="number" className="modal-input" placeholder="Wheat (kg)" style={{ marginBottom: 0 }} onChange={e => setDistribute({...distribute, wheat: e.target.value})} />
              <button className="add-btn" onClick={handleDistribute}>Distribute</button>
            </div>
          </div>
        )}
      </div>

      {data.dailyTransactions.length > 0 && (
        <div className="card">
          <h3>Today's Transactions</h3>
          <table className="data-table">
            <thead><tr><th>ID</th><th>User</th><th>Rice</th><th>Wheat</th><th>Date</th></tr></thead>
            <tbody>
              {data.dailyTransactions.map((tx, i) => (
                <tr key={i}><td>{tx.id}</td><td>{tx.userName || tx.user_id}</td><td>{tx.rice} kg</td><td>{tx.wheat} kg</td><td>{new Date(tx.date).toLocaleTimeString()}</td></tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

/* ========================================
   USER DASHBOARD
   ======================================== */
export function UserDashboard({ user, onLogout }) {
  const [data, setData] = useState(null);

  useEffect(() => {
    if (user?.id) fetch(`${BASE}/user/${user.id}`).then(r => r.json()).then(setData);
  }, [user]);

  if (!data) return <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', color: '#555' }}>Loading Your Dashboard...</div>;

  const chartData = [
    { name: 'Rice', amount: data.entitlement.rice || 0 },
    { name: 'Wheat', amount: data.entitlement.wheat || 0 }
  ];

  return (
    <div style={{ padding: '30px', maxWidth: '1000px', margin: 'auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
        <h2 style={{ color: '#1e3a5f' }}>Hello, {data.user.name}</h2>
        <button className="add-btn" style={{ background: '#e74c3c' }} onClick={onLogout}>Logout</button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: '20px', marginBottom: '25px' }}>
        <div className="card">
          <h3>Personal Details</h3>
          <p style={{ margin: '8px 0' }}><strong>Aadhaar:</strong> {data.user.aadhaar}</p>
          <p style={{ margin: '8px 0' }}><strong>Ration Card:</strong> {data.user.ration_card_number}</p>
          <p style={{ margin: '8px 0' }}><strong>Category:</strong> {data.user.category}</p>
          <p style={{ margin: '8px 0' }}><strong>Family Members:</strong> {data.user.family_members}</p>
        </div>
        <div className="card">
          <h3>Monthly Ration Entitlement</h3>
          <ResponsiveContainer width="100%" height={160}>
            <BarChart layout="vertical" data={chartData} margin={{ left: 30 }}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis type="number" />
              <YAxis type="category" dataKey="name" width={60} />
              <Tooltip />
              <Bar dataKey="amount" fill="#2980b9" radius={[0,5,5,0]} barSize={22} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="card">
        <h3>Transaction History</h3>
        <table className="data-table">
          <thead><tr><th>Date</th><th>Shop</th><th>Rice (kg)</th><th>Wheat (kg)</th></tr></thead>
          <tbody>
            {data.transactionHistory.map((tx, i) => (
              <tr key={i}><td>{new Date(tx.date).toLocaleDateString()}</td><td>{tx.shopName || tx.shop_id}</td><td>{tx.rice}</td><td>{tx.wheat}</td></tr>
            ))}
            {data.transactionHistory.length === 0 && <tr><td colSpan="4" style={{ textAlign: 'center', color: '#999', padding: '30px' }}>No transactions yet</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
}
